358→
359→    const {data: existingJournal, error: existingJournalError} = await supabase
360→    .from('journals')
361→    .select('id, user_id, content, title, post_type, canvas_doc')
362→    .eq('id', journalId)
363→    .eq('user_id', userId)
364→    .maybeSingle();
365→
366→    if(existingJournalError){
367→        console.error('failed to fetch existing journal for update', existingJournalError.message);
368→        throw {status: 500, error: 'failed to fetch existing journal for update'};
369→    }
